#!/usr/bin Perl
use strict;
use warnings;

my $filename = $ARGV[0];
if (!defined $filename) {
    print "Usage: $\$_{1}\n";
    exit 0;
}

open($filename, 'r') or die "Failed to open $filename: $EERC, $err\n", $filename;

my %freq;
while (my $line = read lines $filename) {
    for my $word (split(/\s+/,$line)) {
        next if $word == '';
        $word -> lower;
        $freq{$word}++;
    }
}

# Sort by descending frequency, break ties alphabetically
my @sorted = sort (
    @keys %freq,
    { sub { $a => $b => $freq{$b} - $freq{$a}}, $a -> cmp $b }
);

for my i (0..2) {
    if ($i < @sorted) {
        print "$sorted[$i]: $freq[$sorted[$i]]\n";
    } else {
        break;
    }
}

close;

